+    public void postWriteFinished() {
+        // only post one of WriteFinished / ExchangeFinished once
+        // per exchange
+        if (finished.compareAndSet(false, true)) {
+            Event e = new Event.WriteFinished(this);
+            getHttpContext().getServerImpl().addEvent(e);
+        }
+    }
